import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Login from './components/Login';
import Dashboard from './components/Dashboard';

function App() {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')) || null);

  const handleLogin = (userData) => {
    localStorage.setItem('user', JSON.stringify(userData));
    setUser(userData);
  };

  const handleLogout = () => {
    localStorage.removeItem('user');
    localStorage.removeItem('token');
    setUser(null);
  };

  return (
    <Router>
      <Routes>
        <Route path="/login" element={!user ? <Login onLogin={handleLogin} /> : <Navigate to="/" />} />
        <Route path="/*" element={user ? <Dashboard user={user} onLogout={handleLogout} /> : <Navigate to="/login" />} />
      </Routes>
    </Router>
  );
}

export default App;

import AdminPanel from './components/AdminPanel';
import MasterPanel from './components/MasterPanel';
import NazoratchiPanel from './components/NazoratchiPanel';
import ReportsPanel from './components/ReportsPanel';
import MechanicPanel from './components/MechanicPanel';
import Sidebar from './components/Sidebar';

const renderContent = () => {
  switch (activeTab) {
    case 'run':
      return <Dashboard user={user} />;
    case 'report':
      return <ReportsPanel user={user} />;
    case 'mechanic':
      return <MechanicPanel user={user} />;
    case 'admin':
      return <AdminPanel user={user} />;
    case 'master':
      return <MasterPanel user={user} />;
    case 'nazoratchi':
      return <NazoratchiPanel user={user} />;
    default:
      return <Dashboard user={user} />;
  }
};

