};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Edit2, Save, X } from 'lucide-react';

const AdminPanel = ({ user }) => {
  const [users, setUsers] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [editId, setEditId] = useState(null);
  const [form, setForm] = useState({ username: '', password: '', full_name: '', role: 'MASTER' });
  const [error, setError] = useState('');

  const token = localStorage.getItem('token');
  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
  const API = `http://${window.location.hostname}:8000`;

  const fetchUsers = async () => {
    try {
      const res = await fetch(`${API}/users`, { headers });
      if (res.ok) setUsers(await res.json());
    } catch (e) {}
  };

  useEffect(() => { fetchUsers(); }, []);

  const resetForm = () => {
    setForm({ username: '', password: '', full_name: '', role: 'MASTER' });
    setShowForm(false);
    setEditId(null);
    setError('');
  };

  const handleCreate = async () => {
    if (!form.username || !form.password || !form.full_name) {
      setError('Barcha maydonlarni toldiring');
      return;
    }
    try {
      const res = await fetch(`${API}/users`, {
        method: 'POST', headers, body: JSON.stringify(form)
      });
      if (res.ok) {
        fetchUsers();
        resetForm();
      } else {
        const data = await res.json();
        setError(data.detail || 'Xatolik');
      }
    } catch (e) { setError('Server xatoligi'); }
  };

  const handleUpdate = async () => {
    const body = { full_name: form.full_name, role: form.role };
    if (form.password) body.password = form.password;
    try {
      const res = await fetch(`${API}/users/${editId}`, {
        method: 'PUT', headers, body: JSON.stringify(body)
      });
      if (res.ok) {
        fetchUsers();
        resetForm();
      }
    } catch (e) { setError('Server xatoligi'); }
  };

  const handleDelete = async (id) => {
    if (!confirm('Rostdan ham ochirmoqchimisiz?')) return;
    try {
      await fetch(`${API}/users/${id}`, { method: 'DELETE', headers });
      fetchUsers();
    } catch (e) {}
  };

  const startEdit = (u) => {
    setEditId(u.id);
    setForm({ username: u.username, password: '', full_name: u.full_name, role: u.role });
    setShowForm(true);
    setError('');
  };

  const roleColors = { ADMIN: '#ef4444', MASTER: '#3b82f6', NAZORATCHI: '#22c55e' };

  return (
    <div style={{ padding: '1.5rem' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>Foydalanuvchilar Boshqaruvi</h2>
        <button onClick={() => { resetForm(); setShowForm(true); }} style={{
          display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
          background: 'var(--primary)', color: '#0f172a', border: 'none', borderRadius: '10px',
          cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem'
        }}>
          <Plus size={16} /> Yangi Foydalanuvchi
        </button>
      </div>

      {/* Create/Edit Form */}
      {showForm && (
        <div style={{
          background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px',
          padding: '1.5rem', marginBottom: '1.5rem'
        }}>
          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>
            {editId ? 'Foydalanuvchini Tahrirlash' : 'Yangi Foydalanuvchi'}
          </h3>
          {error && <p style={{ color: '#ef4444', fontSize: '0.85rem', margin: '0 0 1rem 0' }}>{error}</p>}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
            <div>
              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>Username</label>
              <input className="input-field" style={{ marginTop: '4px', marginBottom: '0.5rem' }}
                value={form.username} onChange={e => setForm({...form, username: e.target.value})}
                disabled={!!editId} placeholder="username" />
            </div>
            <div>
              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>
                {editId ? 'Yangi Parol (bosh qoldirish)' : 'Parol'}
              </label>
              <input className="input-field" type="password" style={{ marginTop: '4px', marginBottom: '0.5rem' }}
                value={form.password} onChange={e => setForm({...form, password: e.target.value})}
                placeholder="password" />
            </div>
            <div>
              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>To'liq Ism</label>
              <input className="input-field" style={{ marginTop: '4px', marginBottom: '0.5rem' }}
                value={form.full_name} onChange={e => setForm({...form, full_name: e.target.value})}
                placeholder="Ism Familiya" />
            </div>
            <div>
              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>Rol</label>
              <select className="input-field" style={{ marginTop: '4px', marginBottom: '0.5rem' }}
                value={form.role} onChange={e => setForm({...form, role: e.target.value})}>
                <option value="MASTER">MASTER</option>
                <option value="NAZORATCHI">NAZORATCHI</option>
                <option value="ADMIN">ADMIN</option>
              </select>
            </div>
          </div>
          <div style={{ display: 'flex', gap: '0.5rem', marginTop: '0.5rem' }}>
            <button onClick={editId ? handleUpdate : handleCreate} style={{
              display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 20px',
              background: 'var(--primary)', color: '#0f172a', border: 'none', borderRadius: '10px',
              cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem'
            }}>
              <Save size={14} /> {editId ? 'Saqlash' : 'Yaratish'}
            </button>
            <button onClick={resetForm} style={{
              display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 20px',
              background: 'rgba(255,255,255,0.05)', color: 'var(--text-muted)', border: '1px solid var(--panel-border)',
              borderRadius: '10px', cursor: 'pointer', fontWeight: 600, fontSize: '0.85rem'
            }}>
              <X size={14} /> Bekor Qilish
            </button>
          </div>
        </div>
      )}

      {/* Users Table */}
      <div style={{ background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px', overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ borderBottom: '1px solid var(--panel-border)' }}>
              <th style={thStyle}>ID</th>
              <th style={thStyle}>Username</th>
              <th style={thStyle}>Ism</th>
              <th style={thStyle}>Rol</th>
              <th style={thStyle}>Holat</th>
              <th style={thStyle}>Amallar</th>
            </tr>
          </thead>
          <tbody>
            {users.map(u => (
              <tr key={u.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                <td style={tdStyle}>{u.id}</td>
                <td style={tdStyle}>{u.username}</td>
                <td style={tdStyle}>{u.full_name}</td>
                <td style={tdStyle}>
                  <span style={{
                    padding: '3px 10px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: 700,
                    background: `${roleColors[u.role]}22`, color: roleColors[u.role]
                  }}>{u.role}</span>
                </td>
                <td style={tdStyle}>
                  <span style={{ color: u.is_active ? '#22c55e' : '#ef4444', fontSize: '0.8rem' }}>
                    {u.is_active ? 'Faol' : 'Nofaol'}
                  </span>
                </td>
                <td style={tdStyle}>
                  <div style={{ display: 'flex', gap: '6px' }}>
                    <button onClick={() => startEdit(u)} style={actionBtnStyle('#3b82f6')}>
                      <Edit2 size={14} />
                    </button>
                    {u.id !== user.id && (
                      <button onClick={() => handleDelete(u.id)} style={actionBtnStyle('#ef4444')}>
                        <Trash2 size={14} />
                      </button>
                    )}
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

const thStyle = {
  padding: '12px 16px', textAlign: 'left', fontSize: '0.7rem', fontWeight: 700,
  color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '1px'
};

const tdStyle = {
  padding: '12px 16px', fontSize: '0.85rem', fontWeight: 500
};

const actionBtnStyle = (color) => ({
  padding: '6px', background: `${color}22`, color, border: `1px solid ${color}44`,
  borderRadius: '8px', cursor: 'pointer', display: 'flex', alignItems: 'center'
});

export default AdminPanel;

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Link, Unlink } from 'lucide-react';

const MasterPanel = ({ user }) => {
  const [operators, setOperators] = useState([]);
  const [assignments, setAssignments] = useState([]);
  const [showAddOp, setShowAddOp] = useState(false);
  const [showAssign, setShowAssign] = useState(false);
  const [opForm, setOpForm] = useState({ name: '', phone: '' });
  const [assignForm, setAssignForm] = useState({ operator_id: '', machine_id: '' });
  const [restingToday, setRestingToday] = useState([]);

  const token = localStorage.getItem('token');
  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
  const API = `http://${window.location.hostname}:8000`;

  const fetchData = async () => {
    try {
      const [opsRes, asgRes, restRes] = await Promise.all([
        fetch(`${API}/operators`, { headers }),
        fetch(`${API}/assignments`, { headers }),
        fetch(`${API}/rest-days/today`, { headers }),
      ]);
      if (opsRes.ok) setOperators(await opsRes.json());
      if (asgRes.ok) setAssignments(await asgRes.json());
      if (restRes.ok) setRestingToday(await restRes.json());
    } catch (e) {}
  };

  useEffect(() => { fetchData(); }, []);

  const handleAddOperator = async () => {
    if (!opForm.name) return;
    try {
      const res = await fetch(`${API}/operators`, {
        method: 'POST', headers, body: JSON.stringify(opForm)
      });
      if (res.ok) {
        setOpForm({ name: '', phone: '' });
        setShowAddOp(false);
        fetchData();
      }
    } catch (e) {}
  };

  const handleDeleteOperator = async (id) => {
    if (!confirm('Operatorni ochirmoqchimisiz?')) return;
    try {
      await fetch(`${API}/operators/${id}`, { method: 'DELETE', headers });
      fetchData();
    } catch (e) {}
  };

  const handleAssign = async () => {
    if (!assignForm.operator_id || !assignForm.machine_id) return;
    try {
      const res = await fetch(`${API}/assignments`, {
        method: 'POST', headers, body: JSON.stringify(assignForm)
      });
      if (res.ok) {
        setAssignForm({ operator_id: '', machine_id: '' });
        setShowAssign(false);
        fetchData();
      }
    } catch (e) {}
  };

  const handleUnassign = async (id) => {
    try {
      await fetch(`${API}/assignments/${id}`, { method: 'DELETE', headers });
      fetchData();
    } catch (e) {}
  };

  const isResting = (opId) => restingToday.some(r => r.operator_id === opId);

  return (
    <div style={{ padding: '1.5rem' }}>
      {/* Rest Day Banner */}
      {restingToday.length > 0 && (
        <div style={{
          background: 'rgba(251, 191, 36, 0.1)',
          border: '1px solid rgba(251, 191, 36, 0.3)',
          borderRadius: '16px',
          padding: '1rem 1.5rem',
          marginBottom: '1.5rem',
          display: 'flex',
          alignItems: 'center',
          gap: '12px'
        }}>
          <span style={{ fontSize: '1.5rem' }}>🛏️</span>
          <div>
            <div style={{ fontSize: '0.7rem', fontWeight: 700, color: '#fbbf24', textTransform: 'uppercase', letterSpacing: '1px' }}>
              Bugun dam olganlar
            </div>
            <div style={{ fontSize: '1rem', color: '#fde68a', fontWeight: 700, marginTop: '2px' }}>
              {restingToday.map(r => r.operator_name).join(', ')}
