          </div>
        </div>
      )}

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>Master Panel</h2>
        <div style={{ display: 'flex', gap: '8px' }}>
          <button onClick={() => { setShowAddOp(!showAddOp); setShowAssign(false); }} style={btnStyle('var(--primary)')}>
            <Plus size={16} /> Operator
          </button>
          <button onClick={() => { setShowAssign(!showAssign); setShowAddOp(false); }} style={btnStyle('#a855f7')}>
            <Link size={16} /> Biriktirish
          </button>
        </div>
      </div>

      {/* Add Operator Form */}
      {showAddOp && (
        <div style={formCardStyle}>
          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>Yangi Operator</h3>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
            <div>
              <label style={labelStyle}>Ism</label>
              <input className="input-field" style={inputSmStyle}
                value={opForm.name} onChange={e => setOpForm({ ...opForm, name: e.target.value })}
                placeholder="Operator ismi" />
            </div>
            <div>
              <label style={labelStyle}>Telefon</label>
              <input className="input-field" style={inputSmStyle}
                value={opForm.phone} onChange={e => setOpForm({ ...opForm, phone: e.target.value })}
                placeholder="+998..." />
            </div>
          </div>
          <div style={{ display: 'flex', gap: '8px', marginTop: '0.5rem' }}>
            <button onClick={handleAddOperator} style={btnStyle('var(--primary)')}>Saqlash</button>
            <button onClick={() => setShowAddOp(false)} style={btnStyleSecondary()}>Bekor</button>
          </div>
        </div>
      )}

      {/* Assign Form */}
      {showAssign && (
        <div style={formCardStyle}>
          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>Operatorni Stanokka Biriktirish</h3>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
            <div>
              <label style={labelStyle}>Operator</label>
              <select className="input-field" style={inputSmStyle}
                value={assignForm.operator_id}
                onChange={e => setAssignForm({ ...assignForm, operator_id: parseInt(e.target.value) })}>
                <option value="">Tanlang...</option>
                {operators.filter(o => o.is_active).map(o => (
                  <option key={o.id} value={o.id}>{o.name}</option>
                ))}
              </select>
            </div>
            <div>
              <label style={labelStyle}>Stanok ID</label>
              <select className="input-field" style={inputSmStyle}
                value={assignForm.machine_id}
                onChange={e => setAssignForm({ ...assignForm, machine_id: e.target.value })}>
