          <div style={{ display: 'flex', gap: '8px', marginTop: '0.5rem' }}>
            <button onClick={handleAssign} style={btnStyle('#a855f7')}>Biriktirish</button>
            <button onClick={() => setShowAssign(false)} style={btnStyleSecondary()}>Bekor</button>
          </div>
