              <th style={thStyle}>Operator</th>
              <th style={thStyle}>Telefon</th>
              <th style={thStyle}>Biriktirilgan Stanok</th>
              <th style={thStyle}>Status</th>
              <th style={thStyle}>Amallar</th>
            </tr>
          </thead>
          <tbody>
            {operators.map(op => {
              const opAssignments = assignments.filter(a => a.operator_id === op.id);
              const resting = isResting(op.id);
              return (
                <tr key={op.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                  <td style={tdStyle}>{op.id}</td>
                  <td style={tdStyle}>
