const SIGNAL_TYPES = [
  { value: 'MECHANIC', label: 'Mexanik', color: '#f59e0b', icon: '🔧' },
  { value: 'ELECTRIC', label: 'Elektrik', color: '#3b82f6', icon: '⚡' },
  { value: 'EMERGENCY', label: 'Favqulodda', color: '#ef4444', icon: '🚨' },
  { value: 'ASNOVA', label: 'Asnova', color: '#a855f7', icon: '🧵' },
];

const MechanicPanel = ({ user }) => {
  const [calls, setCalls] = useState([]);
  const [filter, setFilter] = useState('ALL');
  const [showCallForm, setShowCallForm] = useState(false);
  const [callForm, setCallForm] = useState({ machine_id: '', reason: '', signal_type: 'MECHANIC' });
  const audioRef = useRef(null);
  const prevCallsRef = useRef([]);

  const token = localStorage.getItem('token');
  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
  const API = `http://${window.location.hostname}:8000`;

  const playAlert = (signalType) => {
    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      gain.gain.value = 0.3;

      if (signalType === 'EMERGENCY') {
        osc.frequency.value = 880;
        osc.type = 'square';
      } else if (signalType === 'ELECTRIC') {
        osc.frequency.value = 660;
        osc.type = 'sawtooth';
      } else if (signalType === 'ASNOVA') {
        osc.frequency.value = 440;
        osc.type = 'triangle';
      } else {
        osc.frequency.value = 520;
        osc.type = 'sine';
      }

      osc.start();
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 1.5);
      osc.stop(ctx.currentTime + 1.5);
    } catch (e) {}
  };

  const fetchCalls = async () => {
    try {
      const res = await fetch(`${API}/mechanic-calls`, { headers });
      if (res.ok) {
        const data = await res.json();
        const newPending = data.filter(c => c.status === 'PENDING');
        const oldPending = prevCallsRef.current.filter(c => c.status === 'PENDING');
        if (newPending.length > oldPending.length) {
          const newCall = newPending.find(nc => !oldPending.some(oc => oc.id === nc.id));
          if (newCall) {
            playAlert(newCall.signal_type || 'MECHANIC');
          }
        }
        prevCallsRef.current = data;
        setCalls(data);
      }
    } catch (e) {}
  };

  useEffect(() => {
    fetchCalls();
    const i = setInterval(fetchCalls, 3000);
    const h = () => fetchCalls();
    window.addEventListener('app-refresh', h);
    return () => { clearInterval(i); window.removeEventListener('app-refresh', h); };
  }, []);

  const updateStatus = async (id, status) => {
    try {
      await fetch(`${API}/mechanic-calls/${id}`, {
        method: 'PUT', headers, body: JSON.stringify({ status })
      });
      fetchCalls();
      emitRefresh();
    } catch (e) {}
  };

  const handleCreateCall = async () => {
    if (!callForm.machine_id) return;
    try {
      const res = await fetch(`${API}/mechanic-calls`, {
        method: 'POST', headers, body: JSON.stringify(callForm)
      });
      if (res.ok) {
        setCallForm({ machine_id: '', reason: '', signal_type: 'MECHANIC' });
        setShowCallForm(false);
        fetchCalls();
        emitRefresh();
      }
    } catch (e) {}
  };

  const statusColors = {
    PENDING: { bg: 'rgba(251,191,36,0.15)', color: '#fbbf24', icon: <Clock size={14} /> },
    IN_PROGRESS: { bg: 'rgba(59,130,246,0.15)', color: '#3b82f6', icon: <Wrench size={14} /> },
    RESOLVED: { bg: 'rgba(34,197,94,0.15)', color: '#22c55e', icon: <CheckCircle size={14} /> },
  };

  const filtered = filter === 'ALL' ? calls : calls.filter(c => c.status === filter);
  const pendingCount = calls.filter(c => c.status === 'PENDING').length;

  const allMachineIds = Array.from({ length: 68 }, (_, i) => `S${i + 1}`);

  return (
    <div style={{ padding: '1.5rem' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '10px' }}>
          <Wrench size={24} />
          Mexanik Chaqiruvlar
          {pendingCount > 0 && (
            <span style={{
              background: '#ef4444', color: 'white', borderRadius: '50%',
              width: '28px', height: '28px', display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: '0.75rem', fontWeight: 800, animation: 'pulse 1.5s infinite'
            }}>{pendingCount}</span>
          )}
        </h2>
        {(user.role === 'MASTER' || user.role === 'ADMIN' || user.role === 'NAZORATCHI') && (
          <button onClick={() => setShowCallForm(!showCallForm)} style={{
            display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
            background: '#ef4444', color: 'white', border: 'none', borderRadius: '10px',
            cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem'
          }}>
            <AlertTriangle size={16} /> Chaqiruv Yuborish
          </button>
        )}
      </div>

      {showCallForm && (
        <div style={{
          background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px',
          padding: '1.5rem', marginBottom: '1.5rem'
        }}>
          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>Yangi Chaqiruv</h3>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
            <div>
              <label style={labelStyle}>Stanok</label>
              <select className="input-field" style={{ marginTop: '4px' }}
                value={callForm.machine_id}
                onChange={e => setCallForm({ ...callForm, machine_id: e.target.value })}>
                <option value="">Tanlang...</option>
                {allMachineIds.map(id => <option key={id} value={id}>{id}</option>)}
              </select>
            </div>
            <div>
              <label style={labelStyle}>Sabab</label>
              <input className="input-field" style={{ marginTop: '4px' }}
                value={callForm.reason}
                onChange={e => setCallForm({ ...callForm, reason: e.target.value })}
                placeholder="Qisqacha sabab..." />
            </div>
          </div>
          <label style={labelStyle}>Signal Turi</label>
          <div style={{ display: 'flex', gap: '8px', marginTop: '8px', marginBottom: '1rem' }}>
            {SIGNAL_TYPES.map(st => (
              <button key={st.value} onClick={() => setCallForm({ ...callForm, signal_type: st.value })} style={{
                flex: 1, padding: '12px', borderRadius: '10px', border: '2px solid',
                borderColor: callForm.signal_type === st.value ? st.color : 'rgba(255,255,255,0.1)',
                background: callForm.signal_type === st.value ? `${st.color}22` : 'rgba(255,255,255,0.03)',
                color: callForm.signal_type === st.value ? st.color : 'var(--text-muted)',
                cursor: 'pointer', fontWeight: 700, fontSize: '0.8rem', textAlign: 'center'
              }}>
                <div style={{ fontSize: '1.5rem', marginBottom: '4px' }}>{st.icon}</div>
                {st.label}
              </button>
            ))}
          </div>
          <div style={{ display: 'flex', gap: '8px' }}>
            <button onClick={handleCreateCall} style={{
              padding: '10px 20px', background: '#ef4444', color: 'white',
              border: 'none', borderRadius: '10px', cursor: 'pointer', fontWeight: 700
            }}>Yuborish</button>
            <button onClick={() => setShowCallForm(false)} style={{
              padding: '10px 20px', background: 'rgba(255,255,255,0.05)', color: 'var(--text-muted)',
              border: '1px solid var(--panel-border)', borderRadius: '10px', cursor: 'pointer', fontWeight: 600
            }}>Bekor</button>
          </div>
        </div>
      )}

      <div style={{ display: 'flex', gap: '8px', marginBottom: '1.5rem' }}>
        {['ALL', 'PENDING', 'IN_PROGRESS', 'RESOLVED'].map(s => (
          <button key={s} onClick={() => setFilter(s)} style={{
            padding: '8px 16px', borderRadius: '8px',
            border: filter === s ? '2px solid var(--primary)' : '1px solid var(--panel-border)',
            background: filter === s ? 'rgba(0,210,255,0.1)' : 'transparent',
            color: filter === s ? 'var(--primary)' : 'var(--text-muted)',
            cursor: 'pointer', fontWeight: 600, fontSize: '0.8rem'
          }}>
            {s === 'ALL' ? 'Hammasi' : s === 'PENDING' ? 'Kutilmoqda' : s === 'IN_PROGRESS' ? 'Jarayonda' : 'Hal qilingan'}
          </button>
        ))}
      </div>

      <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
        {filtered.length === 0 && (
          <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--text-muted)' }}>
            <CheckCircle size={40} style={{ marginBottom: '1rem', opacity: 0.5 }} />
            <p>Chaqrivlar yo'q</p>
          </div>
        )}
        {filtered.map(call => {
          const sc = statusColors[call.status] || statusColors.PENDING;
          const sig = SIGNAL_TYPES.find(s => s.value === call.signal_type) || SIGNAL_TYPES[0];
          return (
            <div key={call.id} style={{
              background: 'var(--card)', border: `1px solid ${call.status === 'PENDING' ? sig.color + '44' : 'var(--panel-border)'}`,
              borderRadius: '12px', padding: '1rem 1.25rem',
              display: 'flex', alignItems: 'center', justifyContent: 'space-between',
              animation: call.status === 'PENDING' ? 'slideIn 0.3s ease' : 'none'
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                <div style={{
                  width: '44px', height: '44px', borderRadius: '10px',
                  background: `${sig.color}22`, color: sig.color,
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: '1.3rem'
                }}>
                  {sig.icon}
                </div>
                <div>
                  <div style={{ fontWeight: 700, fontSize: '0.9rem' }}>
                    Stanok {call.machine_id}
                    <span style={{
                      marginLeft: '8px', padding: '2px 8px', borderRadius: '4px',
                      fontSize: '0.6rem', fontWeight: 700, background: `${sig.color}22`, color: sig.color
                    }}>{sig.label}</span>
                  </div>
                  <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>
                    {call.reason || 'Sabab ko\'rsatilmagan'} — {new Date(call.created_at).toLocaleString()}
                  </div>
                </div>
              </div>
              <div style={{ display: 'flex', gap: '6px', alignItems: 'center' }}>
                <span style={{
                  padding: '4px 10px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: 700,
                  background: sc.bg, color: sc.color
                }}>
                  {call.status === 'PENDING' ? 'Kutilmoqda' : call.status === 'IN_PROGRESS' ? 'Jarayonda' : 'Hal qilingan'}
                </span>
                {(user.role === 'MECHANIC' || user.role === 'ADMIN') && call.status === 'PENDING' && (
                  <button onClick={() => updateStatus(call.id, 'IN_PROGRESS')} style={{
                    padding: '6px 12px', borderRadius: '8px', background: 'rgba(59,130,246,0.15)',
                    color: '#3b82f6', border: 'none', cursor: 'pointer', fontWeight: 600, fontSize: '0.75rem'
                  }}>Boshlash</button>
                )}
                {(user.role === 'MECHANIC' || user.role === 'ADMIN') && call.status === 'IN_PROGRESS' && (
                  <button onClick={() => updateStatus(call.id, 'RESOLVED')} style={{
                    padding: '6px 12px', borderRadius: '8px', background: 'rgba(34,197,94,0.15)',
                    color: '#22c55e', border: 'none', cursor: 'pointer', fontWeight: 600, fontSize: '0.75rem'
                  }}>Yakunlash</button>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const labelStyle = { fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 };

export default MechanicPanel;

import React from 'react';

const InteractiveMap = ({ machines, onSelectMachine, user, selectedMachine }) => {

  // ═══ KATTA SEX - ongdan chapga, sex ichida ═══
  const generateMainBlock = () => {
    const nodes = [];
    const w = 44, h = 32;
    const gapX = 65;
    const gapY = 70;
    const roomRight = 720;
    const roomTop = 280;

    // 1-49: 5 ta qator (10,10,10,10,9) - ongdan chapga raqamlash
    const rowCounts1 = [10, 10, 10, 10, 9];
    let id = 1;
    rowCounts1.forEach((count, rowIdx) => {
      const rowWidth = count * gapX;
      const startX = roomRight - rowWidth;
      const y = roomTop + rowIdx * gapY;
      // Ongdan chapga: oxirgi raqam o'ngda, birinchi raqam chapda
      for (let i = count - 1; i >= 0; i--) {
        nodes.push({ id: id++, x: startX + i * gapX, y, w, h });
      }
    });

    // 50-60: 2 ta qator (6, 5) - ongdan chapga raqamlash
    const rowCounts2 = [6, 5];
    rowCounts2.forEach((count, rowIdx) => {
      const rowWidth = count * gapX;
      const startX = roomRight - rowWidth;
      const y = roomTop + (5 + rowIdx) * gapY;
      for (let i = count - 1; i >= 0; i--) {
        nodes.push({ id: id++, x: startX + i * gapX, y, w, h });
      }
    });

    return nodes;
  };

  // ═══ KICHKINA SEX - 61-68, yuqoridan pastga ═══
  const generateRightBlock = () => {
    const nodes = [];
    const w = 44, h = 32;
    const startX = 870;
    const startY = 80;
    const gapY = 75;
    for (let i = 0; i < 8; i++) {
      nodes.push({ id: 61 + i, x: startX, y: startY + i * gapY, w, h });
    }
    return nodes;
  };

  const allNodes = [...generateMainBlock(), ...generateRightBlock()];

  const walls = [
    { x1: 30, y1: 30, x2: 960, y2: 30 },
    { x1: 30, y1: 30, x2: 30, y2: 760 },
    { x1: 960, y1: 30, x2: 960, y2: 760 },
    { x1: 30, y1: 760, x2: 960, y2: 760 },
    { x1: 280, y1: 30, x2: 280, y2: 230 },
    { x1: 30, y1: 230, x2: 720, y2: 230 },
    { x1: 720, y1: 30, x2: 720, y2: 760 },
    { x1: 30, y1: 500, x2: 180, y2: 760 },
  ];

  return (
    <div className="factory-bg">
      <svg style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', pointerEvents: 'none' }}>
        {walls.map((w, i) => (
          <line key={`w${i}`} x1={w.x1} y1={w.y1} x2={w.x2} y2={w.y2}
            stroke="#475569" strokeWidth="2" />
        ))}
      </svg>

      <div style={{ position: 'absolute', left: 80, top: 110, color: '#64748b', fontSize: '0.75rem', fontWeight: 700, letterSpacing: '2px', textTransform: 'uppercase' }}>XOMASHYO OMBORI</div>
      <div style={{ position: 'absolute', left: 380, top: 110, color: '#64748b', fontSize: '0.75rem', fontWeight: 700, letterSpacing: '2px', textTransform: 'uppercase' }}>IP YIGIRUV XONASI</div>

      {[200, 500, 800].map((x, i) => (
        <div key={`exit${i}`} style={{
          position: 'absolute', left: x, top: 10,
          background: '#22c55e', padding: '4px 14px', borderRadius: '6px',
          fontSize: '0.65rem', fontWeight: 800, color: '#064e3b',
          boxShadow: '0 0 10px rgba(34,197,94,0.3)'
        }}>▲ CHIQISH</div>
      ))}

      {allNodes.map((node) => {
        const machineData = machines.find((m) => m.id === `S${node.id}`) || { baud: 0, remaining: 0, status: 'OFFLINE' };
        const isConnected = machineData.baud > 0;

        let statusClass = 'stopped';
        let statusMsg = "ESP32 OFF (Aloqa yo'q)";

        if (machineData.status === 'OFFLINE') {
          statusClass = 'stopped';
          statusMsg = "ESP32 OFF (Aloqa yo'q)";
        } else if (machineData.status === 'ESP_ONLINE_NO_SIGNAL') {
          statusClass = 'searching';
          statusMsg = "ESP32 ONLINE | RS485 SIGNAL YO'Q";
        } else if (machineData.status === 'ASNOVA_EMPTY') {
          statusClass = 'warning';
          statusMsg = "STOP (Asnova tugadi)";
        } else if (machineData.status === 'RUNNING') {
          statusClass = 'running';
          statusMsg = "ISHLAYAPTI";
        }

        const isRunning = statusClass === 'running';
        const isFocused = selectedMachine?.id === `S${node.id}`;

        return (
          <div
            key={node.id}
            className={`machine-node ${statusClass} ${isRunning ? 'pulse-neon' : ''} ${isFocused ? 'is-focused' : ''}`}
            style={{ left: `${node.x}px`, top: `${node.y}px`, width: `${node.w}px`, height: `${node.h}px` }}
            onClick={() => onSelectMachine({ ...machineData, displayStatus: statusMsg, id: `S${node.id}` })}
            title={`S${node.id} | ${statusMsg}`}
          >
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1px', position: 'relative' }}>
              {isFocused && <div className="smart-pulse"></div>}
              <svg width="22" height="16" viewBox="0 0 24 24" fill="currentColor"
                style={{ opacity: isConnected ? 1 : 0.35 }}>
                <path d="M2,14 L2,18 L22,18 L22,14 M4,14 L4,6 L20,6 L20,14 M6,10 L18,10 M2,8 L2,20 L22,20 L22,8 L20,8 L20,4 L4,4 L4,8 Z" />
                <rect x="7" y="11" width="10" height="3"
                  opacity={isRunning ? 0.9 : 0.15}
                  className={isRunning ? 'shuttle-anim' : ''} />
              </svg>
              <span style={{ fontSize: '0.55rem', letterSpacing: '0.5px', fontWeight: 800, lineHeight: 1 }}>
                {node.id}
              </span>
            </div>
          </div>
        );
      })}
    </div>
  );
};

export default InteractiveMap;

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Edit2, Save, X } from 'lucide-react';

const AdminPanel = ({ user }) => {
  const [users, setUsers] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [editId, setEditId] = useState(null);
  const [form, setForm] = useState({ username: '', password: '', full_name: '', role: 'MASTER' });
  const [error, setError] = useState('');

  const token = localStorage.getItem('token');
  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
  const API = `http://${window.location.hostname}:8000`;

  const roleColors = { ADMIN: '#ef4444', MASTER: '#3b82f6', NAZORATCHI: '#22c55e', MECHANIC: '#f59e0b' };

  const fetchUsers = async () => {
    try {
      const res = await fetch(`${API}/users`, { headers });
      if (res.ok) setUsers(await res.json());
    } catch (e) {}
  };

  useEffect(() => { fetchUsers(); }, []);

  const resetForm = () => {
    setForm({ username: '', password: '', full_name: '', role: 'MASTER' });
    setShowForm(false);
    setEditId(null);
    setError('');
  };

  const handleCreate = async () => {
    if (!form.username || !form.password || !form.full_name) {
      setError('Barcha maydonlarni toldiring');
      return;
    }
    try {
      const res = await fetch(`${API}/users`, {
        method: 'POST', headers, body: JSON.stringify(form)
      });
      if (res.ok) {
        fetchUsers();
        resetForm();
      } else {
        const data = await res.json();
        setError(data.detail || 'Xatolik');
      }
    } catch (e) { setError('Server xatoligi'); }
  };

  const handleUpdate = async () => {
    const body = { full_name: form.full_name, role: form.role };
    if (form.password) body.password = form.password;
    try {
      const res = await fetch(`${API}/users/${editId}`, {
        method: 'PUT', headers, body: JSON.stringify(body)
      });
      if (res.ok) {
        fetchUsers();
        resetForm();
      }
    } catch (e) { setError('Server xatoligi'); }
  };

  const handleDelete = async (id) => {
    if (!confirm('Rostdan ham ochirmoqchimisiz?')) return;
    try {
      await fetch(`${API}/users/${id}`, { method: 'DELETE', headers });
      fetchUsers();
    } catch (e) {}
  };

  const startEdit = (u) => {
    setEditId(u.id);
    setForm({ username: u.username, password: '', full_name: u.full_name, role: u.role });
    setShowForm(true);
    setError('');
  };

  return (
    <div style={{ padding: '1.5rem' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>Foydalanuvchilar Boshqaruvi</h2>
        <button onClick={() => { resetForm(); setShowForm(true); }} style={{
          display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
          background: 'var(--primary)', color: '#0f172a', border: 'none', borderRadius: '10px',
          cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem'
        }}>
          <Plus size={16} /> Yangi Foydalanuvchi
        </button>
      </div>

      {showForm && (
        <div style={{
          background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px',
          padding: '1.5rem', marginBottom: '1.5rem'
        }}>
          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>
            {editId ? 'Foydalanuvchini Tahrirlash' : 'Yangi Foydalanuvchi'}
          </h3>
          {error && <p style={{ color: '#ef4444', fontSize: '0.85rem', margin: '0 0 1rem 0' }}>{error}</p>}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
            <div>
              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>Username</label>
              <input className="input-field" style={{ marginTop: '4px', marginBottom: '0.5rem' }}
                value={form.username} onChange={e => setForm({...form, username: e.target.value})}
                disabled={!!editId} placeholder="username" />
            </div>
            <div>
              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>
                {editId ? 'Yangi Parol (bosh qoldirish)' : 'Parol'}
              </label>
              <input className="input-field" type="password" style={{ marginTop: '4px', marginBottom: '0.5rem' }}
                value={form.password} onChange={e => setForm({...form, password: e.target.value})}
                placeholder="password" />
            </div>
            <div>
              <label style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>To'liq Ism</label>
              <input className="input-field" style={{ marginTop: '4px', marginBottom: '0.5rem' }}
                value={form.full_name} onChange={e => setForm({...form, full_name: e.target.value})}
                placeholder="Ism Familiya" />
            </div>
