          <button onClick={() => { setShowCallForm(!showCallForm); setShowReasons(false); setSelectedReasons([]); setCustomReason(''); }} style={{
            display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
            background: '#ef4444', color: 'white', border: 'none', borderRadius: '10px',
            cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem'
          }}>
            <AlertTriangle size={16} /> Chaqiruv Yuborish
          </button>
        )}
      </div>

      {showCallForm && (
        <div style={{
          background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px',
          padding: '1.5rem', marginBottom: '1.5rem'
        }}>
          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>Yangi Chaqiruv</h3>

          <div style={{ marginBottom: '1rem' }}>
            <label style={labelStyle}>Stanok</label>
            <select className="input-field" style={{ marginTop: '4px' }}
              value={callForm.machine_id}
              onChange={e => setCallForm({ ...callForm, machine_id: e.target.value })}>
              <option value="">Tanlang...</option>
              {allMachineIds.map(id => <option key={id} value={id}>{id}</option>)}
            </select>
          </div>

          <label style={labelStyle}>Signal Turi</label>
          <div style={{ display: 'flex', gap: '8px', marginTop: '8px', marginBottom: '1rem' }}>
            {SIGNAL_TYPES.map(st => (
              <button key={st.value} onClick={() => handleSignalChange(st.value)} style={{
                flex: 1, padding: '12px', borderRadius: '10px', border: '2px solid',
                borderColor: callForm.signal_type === st.value ? st.color : 'rgba(255,255,255,0.1)',
                background: callForm.signal_type === st.value ? `${st.color}22` : 'rgba(255,255,255,0.03)',
                color: callForm.signal_type === st.value ? st.color : 'var(--text-muted)',
                cursor: 'pointer', fontWeight: 700, fontSize: '0.8rem', textAlign: 'center'
              }}>
                <div style={{ fontSize: '1.5rem', marginBottom: '4px' }}>{st.icon}</div>
                {st.label}
              </button>
            ))}
          </div>

          <div style={{
            maxHeight: showReasons ? '500px' : '0',
            overflow: 'hidden',
            transition: 'max-height 0.4s ease, opacity 0.3s ease',
            opacity: showReasons ? 1 : 0,
          }}>
            <label style={labelStyle}>Sababni tanlang (bir nechta tanlash mumkin)</label>
            <div style={{
              display: 'flex', flexWrap: 'wrap', gap: '8px', marginTop: '8px',
              padding: '12px', background: 'rgba(0,0,0,0.2)', borderRadius: '12px'
            }}>
              {currentReasons.map(reason => {
                const isSelected = selectedReasons.includes(reason);
                const isOther = reason === 'Boshqa';
                return (
                  <button key={reason} onClick={() => toggleReason(reason)} style={{
                    padding: '8px 16px', borderRadius: '20px',
                    border: `2px solid ${isSelected ? (isOther ? '#a855f7' : '#22c55e') : 'rgba(255,255,255,0.1)'}`,
                    background: isSelected ? (isOther ? 'rgba(168,85,247,0.2)' : 'rgba(34,197,94,0.15)') : 'rgba(255,255,255,0.03)',
                    color: isSelected ? (isOther ? '#a855f7' : '#22c55e') : 'var(--text-muted)',
                    cursor: 'pointer', fontWeight: 600, fontSize: '0.8rem',
                    transition: 'all 0.2s ease',
                  }}>
                    {isSelected ? '✓ ' : ''}{reason}
                  </button>
                );
              })}
            </div>

            {hasOther && (
              <div style={{ marginTop: '0.75rem' }}>
                <input className="input-field" style={{ marginTop: '4px' }}
                  value={customReason}
                  onChange={e => setCustomReason(e.target.value)}
                  placeholder="Sababni yozing..." autoFocus />
              </div>
            )}
          </div>

          <div style={{ display: 'flex', gap: '8px', marginTop: '1rem' }}>
            <button onClick={handleCreateCall} disabled={!callForm.machine_id || (selectedReasons.length === 0 && !customReason)} style={{
              padding: '10px 20px',
              background: (!callForm.machine_id || (selectedReasons.length === 0 && !customReason)) ? 'rgba(239,68,68,0.3)' : '#ef4444',
              color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', fontWeight: 700
            }}>Yuborish</button>
            <button onClick={() => { setShowCallForm(false); setShowReasons(false); setSelectedReasons([]); setCustomReason(''); }} style={{
              padding: '10px 20px', background: 'rgba(255,255,255,0.05)', color: 'var(--text-muted)',
              border: '1px solid var(--panel-border)', borderRadius: '10px', cursor: 'pointer', fontWeight: 600
            }}>Bekor</button>
          </div>
        </div>
      )}

      <div style={{ display: 'flex', gap: '8px', marginBottom: '1.5rem' }}>
        {['ALL', 'PENDING', 'IN_PROGRESS', 'RESOLVED'].map(s => (
          <button key={s} onClick={() => setFilter(s)} style={{
            padding: '8px 16px', borderRadius: '8px',
            border: filter === s ? '2px solid var(--primary)' : '1px solid var(--panel-border)',
            background: filter === s ? 'rgba(0,210,255,0.1)' : 'transparent',
            color: filter === s ? 'var(--primary)' : 'var(--text-muted)',
            cursor: 'pointer', fontWeight: 600, fontSize: '0.8rem'
          }}>
            {s === 'ALL' ? 'Hammasi' : s === 'PENDING' ? 'Kutilmoqda' : s === 'IN_PROGRESS' ? 'Jarayonda' : 'Hal qilingan'}
          </button>
        ))}
      </div>

      <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
        {filtered.length === 0 && (
          <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--text-muted)' }}>
            <CheckCircle size={40} style={{ marginBottom: '1rem', opacity: 0.5 }} />
            <p>Chaqrivlar yo'q</p>
          </div>
        )}
        {filtered.map(call => {
          const sc = statusColors[call.status] || statusColors.PENDING;
          const sig = SIGNAL_TYPES.find(s => s.value === call.signal_type) || SIGNAL_TYPES[0];
          return (
            <div key={call.id} style={{
              background: 'var(--card)', border: `1px solid ${call.status === 'PENDING' ? sig.color + '44' : 'var(--panel-border)'}`,
              borderRadius: '12px', padding: '1rem 1.25rem',
              display: 'flex', alignItems: 'center', justifyContent: 'space-between',
              animation: call.status === 'PENDING' ? 'slideIn 0.3s ease' : 'none'
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                <div style={{
                  width: '44px', height: '44px', borderRadius: '10px',
                  background: `${sig.color}22`, color: sig.color,
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: '1.3rem'
                }}>
                  {sig.icon}
                </div>
                <div>
                  <div style={{ fontWeight: 700, fontSize: '0.9rem' }}>
                    Stanok {call.machine_id}
                    <span style={{
                      marginLeft: '8px', padding: '2px 8px', borderRadius: '4px',
                      fontSize: '0.6rem', fontWeight: 700, background: `${sig.color}22`, color: sig.color
                    }}>{sig.label}</span>
                  </div>
                  <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>
                    {call.reason || "Sabab ko'rsatilmagan"} — {new Date(call.created_at).toLocaleString()}
                  </div>
                </div>
              </div>
              <div style={{ display: 'flex', gap: '6px', alignItems: 'center' }}>
                <span style={{
                  padding: '4px 10px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: 700,
                  background: sc.bg, color: sc.color
                }}>
                  {call.status === 'PENDING' ? 'Kutilmoqda' : call.status === 'IN_PROGRESS' ? 'Jarayonda' : 'Hal qilingan'}
                </span>
                {(user.role === 'MECHANIC' || user.role === 'ELECTRIC' || user.role === 'ADMIN') && call.status === 'PENDING' && (
                  <button onClick={() => updateStatus(call.id, 'IN_PROGRESS')} style={{
                    padding: '6px 12px', borderRadius: '8px', background: 'rgba(59,130,246,0.15)',
                    color: '#3b82f6', border: 'none', cursor: 'pointer', fontWeight: 600, fontSize: '0.75rem'
                  }}>Qabul qilish</button>
                )}
                {(user.role === 'MECHANIC' || user.role === 'ELECTRIC' || user.role === 'ADMIN') && call.status === 'IN_PROGRESS' && (
                  <button onClick={() => updateStatus(call.id, 'RESOLVED')} style={{
                    padding: '6px 12px', borderRadius: '8px', background: 'rgba(34,197,94,0.15)',
                    color: '#22c55e', border: 'none', cursor: 'pointer', fontWeight: 600, fontSize: '0.75rem'
                  }}>Yakunlash</button>
                )}
                {canForward(call) && (
                  <div style={{ position: 'relative' }}>
                    <button onClick={() => setForwardCall(forwardCall === call.id ? null : call.id)} style={{
                      padding: '6px 12px', borderRadius: '8px', background: 'rgba(168,85,247,0.15)',
                      color: '#a855f7', border: 'none', cursor: 'pointer', fontWeight: 600, fontSize: '0.75rem',
                      display: 'flex', alignItems: 'center', gap: '4px'
                    }}>
                      <ArrowRight size={12} /> Yo'naltirish
                    </button>
                    {forwardCall === call.id && (
                      <div style={{
                        position: 'absolute', top: '100%', right: 0, marginTop: '4px',
                        background: 'var(--card)', border: '1px solid var(--panel-border)',
                        borderRadius: '10px', padding: '8px', zIndex: 10,
                        boxShadow: '0 8px 24px rgba(0,0,0,0.4)'
                      }}>
                        {forwardTargets(call).map(ft => (
                          <button key={ft.value} onClick={() => handleForward(call.id, ft.value)} style={{
                            display: 'flex', alignItems: 'center', gap: '8px',
                            padding: '8px 16px', borderRadius: '8px', border: 'none',
                            background: 'rgba(255,255,255,0.05)', color: 'var(--text-main)',
                            cursor: 'pointer', fontWeight: 600, fontSize: '0.8rem', width: '100%'
                          }}>
                            <span>{ft.icon}</span> {ft.label}
                          </button>
                        ))}
                      </div>
                    )}
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const labelStyle = { fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 };

