  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import { Calendar, ChevronLeft, ChevronRight, Plus, Trash2, Save, X } from 'lucide-react';
import { emitRefresh } from '../utils/events';

const DAYS = ['Dush', 'Sesh', 'Chor', 'Pay', 'Jum', 'Shan', 'Yak'];
const DAYS_FULL = ['Dushanba', 'Seshanba', 'Chorshanba', 'Payshanba', 'Juma', 'Shanba', 'Yakshanba'];

const NazoratchiPanel = ({ user }) => {
  const [operators, setOperators] = useState([]);
  const [restDays, setRestDays] = useState([]);
  const [weekStart, setWeekStart] = useState(getMonday(new Date()));
  const [users, setUsers] = useState([]);
  const [showUserForm, setShowUserForm] = useState(false);
  const [userForm, setUserForm] = useState({ username: '', password: '', full_name: '', role: 'MASTER' });
  const [userError, setUserError] = useState('');

  const token = localStorage.getItem('token');
  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
  const API = `http://${window.location.hostname}:8000`;

  function getMonday(d) {
    const date = new Date(d);
    const day = date.getDay();
    const diff = date.getDate() - day + (day === 0 ? -6 : 1);
    date.setDate(diff);
    return date.toISOString().split('T')[0];
  }

  const fetchData = async () => {
    try {
      const [opsRes, restRes, usersRes] = await Promise.all([
        fetch(`${API}/operators`, { headers }),
        fetch(`${API}/rest-days?week_start=${weekStart}`, { headers }),
        fetch(`${API}/users`, { headers }),
      ]);
      if (opsRes.ok) setOperators(await opsRes.json());
      if (restRes.ok) setRestDays(await restRes.json());
      if (usersRes.ok) {
        const allUsers = await usersRes.json();
        setUsers(allUsers.filter(u => u.role !== 'ADMIN'));
      }
    } catch (e) {}
  };

  useEffect(() => { fetchData(); }, [weekStart]);
  useEffect(() => { const h = () => fetchData(); window.addEventListener('app-refresh', h); return () => window.removeEventListener('app-refresh', h); }, [weekStart]);

  const toggleRestDay = async (operatorId, dayOfWeek) => {
    try {
      await fetch(`${API}/rest-days`, {
        method: 'POST', headers,
        body: JSON.stringify({ operator_id: operatorId, day_of_week: dayOfWeek, week_start: weekStart })
      });
      fetchData();
      emitRefresh();
    } catch (e) {}
  };

  const isResting = (opId, dow) => restDays.some(r => r.operator_id === opId && r.day_of_week === dow);

  const shiftWeek = (offset) => {
    const d = new Date(weekStart);
    d.setDate(d.getDate() + offset * 7);
    setWeekStart(d.toISOString().split('T')[0]);
  };

  const weekLabel = () => {
    const start = new Date(weekStart);
    const end = new Date(weekStart);
    end.setDate(end.getDate() + 6);
    return `${start.toLocaleDateString('uz')} - ${end.toLocaleDateString('uz')}`;
  };

  const handleCreateUser = async () => {
    if (!userForm.username || !userForm.password || !userForm.full_name) {
      setUserError('Barcha maydonlarni toldiring');
      return;
    }
    try {
      const res = await fetch(`${API}/users`, { method: 'POST', headers, body: JSON.stringify(userForm) });
      if (res.ok) {
        setUserForm({ username: '', password: '', full_name: '', role: 'MASTER' });
        setShowUserForm(false);
        setUserError('');
        fetchData();
      } else {
        const data = await res.json();
        setUserError(data.detail || 'Xatolik');
      }
    } catch (e) { setUserError('Server xatoligi'); }
  };

  const handleDeleteUser = async (id) => {
    if (!confirm('Rostdan ham ochirmoqchimisiz?')) return;
    try {
      await fetch(`${API}/users/${id}`, { method: 'DELETE', headers });
      fetchData();
    } catch (e) {}
  };

  const roleColors = { MASTER: '#3b82f6', NAZORATCHI: '#22c55e', MECHANIC: '#f59e0b', ELECTRIC: '#06b6d4', UZLAVYAZ: '#a855f7' };

  return (
    <div style={{ padding: '1.5rem' }}>
      {/* Dam olish jadvali */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>
          <Calendar size={24} style={{ marginRight: '8px', verticalAlign: 'middle' }} />
          Dam Olish Jadvali
        </h2>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <button onClick={() => shiftWeek(-1)} style={navBtnStyle}><ChevronLeft size={16} /></button>
          <span style={{ fontSize: '0.9rem', fontWeight: 700, color: 'var(--primary)', minWidth: '200px', textAlign: 'center' }}>
            {weekLabel()}
          </span>
          <button onClick={() => shiftWeek(1)} style={navBtnStyle}><ChevronRight size={16} /></button>
        </div>
      </div>

      <div style={{ background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px', overflow: 'hidden', marginBottom: '2rem' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ borderBottom: '1px solid var(--panel-border)' }}>
              <th style={thStyle}>Operator</th>
              {DAYS.map((d, i) => (
                <th key={i} style={{ ...thStyle, textAlign: 'center' }}>{d}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {operators.filter(o => o.is_active).map(op => (
              <tr key={op.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                <td style={tdStyle}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <div style={{
                      width: '32px', height: '32px', borderRadius: '8px',
                      background: 'rgba(0,210,255,0.15)',
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      fontSize: '0.8rem', fontWeight: 800, color: 'var(--primary)'
                    }}>
                      {op.name.charAt(0).toUpperCase()}
                    </div>
                    <span style={{ fontWeight: 600 }}>{op.name}</span>
                  </div>
                </td>
                {DAYS.map((_, dow) => {
                  const resting = isResting(op.id, dow);
                  return (
                    <td key={dow} style={{ ...tdStyle, textAlign: 'center' }}>
                      <button
                        onClick={() => toggleRestDay(op.id, dow)}
                        style={{
                          width: '36px', height: '36px', borderRadius: '8px',
                          border: resting ? '2px solid #fbbf24' : '1px solid var(--panel-border)',
                          background: resting ? 'rgba(251,191,36,0.2)' : 'rgba(255,255,255,0.03)',
                          color: resting ? '#fbbf24' : 'var(--text-muted)',
                          cursor: 'pointer', fontSize: '1rem', fontWeight: 700,
                          transition: 'all 0.2s'
                        }}
                        title={DAYS_FULL[dow]}
                      >
                        {resting ? '🛏️' : '○'}
                      </button>
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Foydalanuvchilar boshqaruvi */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>Foydalanuvchilar</h2>
        <button onClick={() => { setShowUserForm(!showUserForm); setUserError(''); }} style={{
          display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
          background: 'var(--primary)', color: '#0f172a', border: 'none', borderRadius: '10px',
          cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem'
        }}>
          <Plus size={16} /> Yangi Foydalanuvchi
        </button>
      </div>

      {showUserForm && (
        <div style={{
          background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px',
          padding: '1.5rem', marginBottom: '1.5rem'
        }}>
          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>Yangi Foydalanuvchi</h3>
          {userError && <p style={{ color: '#ef4444', fontSize: '0.85rem', margin: '0 0 1rem 0' }}>{userError}</p>}
