async def get_monthly_report_excel(month: Optional[str] = None, db: Session = Depends(database.get_db), current_user: models.User = Depends(get_current_user)):
    """Monthly operator report as Excel with meters, plan, percentage."""
    import pandas as pd
    if not month:
        month = datetime.utcnow().strftime("%Y-%m")

    start_of_month = datetime.strptime(month, "%Y-%m")
    import calendar
    year, mon = map(int, month.split('-'))
    days_in_month = calendar.monthrange(year, mon)[1]

    operators = db.query(models.Operator).filter(
        models.Operator.is_active == 1,
        models.Operator.position == "Operator"
    ).all()

    logs = db.query(models.ProductionLog).filter(
        ProductionLog.date >= start_of_month,
        ProductionLog.date < start_of_month + timedelta(days=days_in_month)
    ).all() if 'ProductionLog' in dir(models) else []

    # Build operator daily data
    op_daily = {}
    for op in operators:
        op_daily[op.id] = {"name": op.name, "machine": "", "days": {}, "total": 0}

    for l in logs:
        if l.operator_id in op_daily:
            day = l.date.day
            op_daily[l.operator_id]["days"][day] = op_daily[l.operator_id]["days"].get(day, 0) + l.meters_woven
            op_daily[l.operator_id]["total"] += l.meters_woven
            op_daily[l.operator_id]["machine"] = l.machine_id

    # Get assignments for machine info
    assignments = db.query(models.Assignment).filter(models.Assignment.is_active == 1).all()
    for a in assignments:
        if a.operator_id in op_daily and not op_daily[a.operator_id]["machine"]:
            op_daily[a.operator_id]["machine"] = a.machine_id

    plan_per_day = 100  # Default plan meters per day

    rows = []
    for op_id, info in op_daily.items():
        row = {"Operator": info["name"], "Stanok": info["machine"]}
        total = 0
        for d in range(1, days_in_month + 1):
            meters = info["days"].get(d, 0)
            row[f"{d}"] = round(meters, 1) if meters > 0 else ""
            total += meters
        row["Jami metr"] = round(total, 1)
        row["Reja"] = plan_per_day * days_in_month
        row["Bajarish %"] = round((total / (plan_per_day * days_in_month)) * 100, 1) if plan_per_day * days_in_month > 0 else 0
        rows.append(row)

    df = pd.DataFrame(rows)
    output = io.BytesIO()
    with pd.ExcelWriter(output, engine='openpyxl') as writer:
        df.to_excel(writer, index=False, sheet_name=f'Operator {month}')
    output.seek(0)
    return StreamingResponse(output, media_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
                            headers={"Content-Disposition": f"attachment; filename=operator_report_{month}.xlsx"})

