  const [wsConnected, setWsConnected] = useState(false);
  const wsRef = useRef(null);
  const reconnectTimeoutRef = useRef(null);

  // WebSocket connection for real-time updates
  useEffect(() => {
    const connectWebSocket = () => {
      const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
      const wsUrl = `${protocol}//${window.location.host}/ws/machines`;

      wsRef.current = new WebSocket(wsUrl);

      wsRef.current.onopen = () => {
        console.log('WebSocket connected');
        setWsConnected(true);
      };

      wsRef.current.onmessage = (event) => {
        try {
          const data = JSON.parse(event.data);
          setMachines(data);
        } catch (e) {
          console.error('Error parsing WebSocket message:', e);
        }
      };

      wsRef.current.onclose = () => {
        console.log('WebSocket disconnected');
        setWsConnected(false);
        // Attempt to reconnect after 3 seconds
        reconnectTimeoutRef.current = setTimeout(connectWebSocket, 3000);
      };

      wsRef.current.onerror = (error) => {
        console.error('WebSocket error:', error);
        wsRef.current.close();
      };
    };

    connectWebSocket();

    return () => {
      if (wsRef.current) {
        wsRef.current.close();
      }
      if (reconnectTimeoutRef.current) {
        clearTimeout(reconnectTimeoutRef.current);
      }
    };
  }, []);

  // Fallback to HTTP polling if WebSocket fails
  useEffect(() => {
    if (wsConnected) return;

    const fetchMachines = async () => {
      try {
        const token = localStorage.getItem("token");
        if (!token) return;
        const res = await fetch(`${API}/machines`, {
          headers: { "Authorization": `Bearer ${token}` }
        });
        if (res.ok) {
          const data = await res.json();
          if (data.length > 0) setMachines(data);
        }
      } catch (e) {}
    };

    fetchMachines();
    const interval = setInterval(fetchMachines, 5000);
    return () => clearInterval(interval);
  }, [wsConnected]);

  useEffect(() => {
    if (selectedMachine) {
      fetch(`${API}/machines/${selectedMachine.id}/watch`, {
        method: "POST",
        headers: { "Authorization": `Bearer ${localStorage.getItem("token")}` }
      }).catch(err => console.error("Watch trigger failed", err));
    }
  }, [selectedMachine]);

  const handleFillAsnova = async () => {
    if (!asnovaLength || !selectedMachine) return;
    try {
      const response = await fetch(`${API}/machines/${selectedMachine.id}/fill`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${localStorage.getItem("token")}`
        },
        body: JSON.stringify({
          initial_asnova_length: parseFloat(asnovaLength),
          last_operator_id: user.id
        })
      });

      if (response.ok) {
        alert("Asnova muvaffaqiyatli toldirildi!");
        setSelectedMachine(null);
        setAsnovaLength("");
      }
    } catch (err) {
      alert("Xatolik yuz berdi");
    }
  };

  const handleSourceChange = async (machineId, newSource) => {
    try {
      await fetch(`${API}/machines/${machineId}/source?preferred_source=${newSource}`, {
        method: "POST",
        headers: { "Authorization": `Bearer ${localStorage.getItem('token')}` }
      });
    } catch (err) {
      alert("Xatolik: Manbani o'zgartirib bo'lmadi");
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'RUNNING': return 'var(--success)';
      case 'OFFLINE': return 'var(--text-muted)';
      case 'ASNOVA_EMPTY': return 'var(--danger)';
      case 'ESP_ONLINE_NO_SIGNAL': return 'var(--warning)';
      default: return 'var(--text-muted)';
    }
  };

  const getStatusText = (status) => {
    switch (status) {
      case 'RUNNING': return 'Ishlamoqda';
      case 'OFFLINE': return 'Offline';
      case 'ASNOVA_EMPTY': return 'Asnova tugagan';
      case 'ESP_ONLINE_NO_SIGNAL': return 'Signal yo\'q';
      default: return 'Noma\'lum';
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'RUNNING': return <Play size={14} />;
      case 'OFFLINE': return <WifiOff size={14} />;
      case 'ASNOVA_EMPTY': return <AlertTriangle size={14} />;
      case 'ESP_ONLINE_NO_SIGNAL': return <Signal size={14} />;
      default: return <AlertCircle size={14} />;
    }
  };

  const filteredMachines = useMemo(() => {
    return machines.filter(machine => {
      const matchesFilter = filter === 'all' || machine.status === filter;
      const matchesSearch = machine.id.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesFilter && matchesSearch;
    });
  }, [machines, filter, searchQuery]);

  const stats = useMemo(() => ({
    total: machines.length,
    running: machines.filter(m => m.status === 'RUNNING').length,
    stopped: machines.filter(m => m.status === 'ASNOVA_EMPTY' || m.status === 'STOPPED' || m.status === 'OFFLINE').length,
    warning: machines.filter(m => m.status === 'ESP_ONLINE_NO_SIGNAL').length
  }), [machines]);

  const MachineCard = ({ machine }) => {
    const statusColor = getStatusColor(machine.status);
    const statusText = getStatusText(machine.status);
    const statusIcon = getStatusIcon(machine.status);

    return (
      <div 
        className={`machine-card ${machine.status.toLowerCase()}`}
        onClick={() => {
          setSelectedMachine(machine);
          setActiveTab('info');
        }}
      >
        <div className="machine-card-header">
          <div className="machine-card-id">{machine.id}</div>
          <div className="machine-card-status" style={{ color: statusColor }}>
            {statusIcon}
            <span>{statusText}</span>
          </div>
        </div>

        <div className="machine-card-body">
          <div className="machine-card-meters">
            <div className="meter-item">
              <span className="meter-label">Smena</span>
              <span className="meter-value">{machine.shift_meters?.toFixed(1) || 0}m</span>
            </div>
            <div className="meter-item">
              <span className="meter-label">Asnova</span>
              <span className="meter-value">{machine.remaining?.toFixed(1) || 0}m</span>
            </div>
          </div>

          <div className="machine-card-signal">
            <Signal size={12} />
            <span>{machine.baud || 0} BPS</span>
          </div>
        </div>

        <div className="machine-card-footer">
          <div className="machine-card-source">
            {machine.connection_source === 'WIFI' ? <Wifi size={12} /> : <Usb size={12} />}
            <span>{machine.connection_source}</span>
          </div>
          <div className="machine-card-time">
            <Clock size={12} />
            <span>{machine.last_seen ? new Date(machine.last_seen).toLocaleTimeString('uz-UZ') : 'N/A'}</span>
          </div>
        </div>
      </div>
    );
  };

  const MachineListItem = ({ machine }) => {
    const statusColor = getStatusColor(machine.status);
    const statusText = getStatusText(machine.status);

    return (
      <div 
        className="machine-list-item"
        onClick={() => {
          setSelectedMachine(machine);
          setActiveTab('info');
        }}
      >
        <div className="machine-list-id">{machine.id}</div>
        <div className="machine-list-status" style={{ color: statusColor }}>
          {getStatusIcon(machine.status)}
          <span>{statusText}</span>
        </div>
        <div className="machine-list-meters">
          <span>{machine.shift_meters?.toFixed(1) || 0}m</span>
          <span className="separator">/</span>
          <span>{machine.remaining?.toFixed(1) || 0}m</span>
        </div>
        <div className="machine-list-signal">
          <Signal size={12} />
          <span>{machine.baud || 0}</span>
        </div>
        <div className="machine-list-source">
          {machine.connection_source === 'WIFI' ? <Wifi size={12} /> : <Usb size={12} />}
        </div>
      </div>
    );
  };

  return (
    <div className="dashboard">
      {/* Header */}
      <div className="dashboard-header">
        <div className="dashboard-title">
          <h1>Monitoring</h1>
          <p className="dashboard-subtitle">Real-time machine monitoring</p>
        </div>

        <div className="dashboard-controls">
          <div className="search-box">
            <Search size={16} />
            <input
              type="text"
              placeholder="Qidiruv..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>

          <div className="view-toggle">
            <button 
              className={`view-btn ${viewMode === 'grid' ? 'active' : ''}`}
              onClick={() => setViewMode('grid')}
            >
              <Grid size={16} />
            </button>
            <button 
              className={`view-btn ${viewMode === 'list' ? 'active' : ''}`}
              onClick={() => setViewMode('list')}
            >
              <List size={16} />
            </button>
          </div>

          <div className="connection-status">
            {wsConnected ? (
              <div className="status-connected">
                <Wifi size={14} />
                <span>Live</span>
              </div>
            ) : (
              <div className="status-disconnected">
                <WifiOff size={14} />
                <span>Offline</span>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Stats */}
      <div className="stats-row">
        <div className="stat-card">
          <div className="stat-card-header">
            <div className="stat-card-icon blue">
              <Layers size={18} />
            </div>
            <div className="stat-card-label">Jami</div>
          </div>
          <div className="stat-card-value">{stats.total}</div>
        </div>

        <div className="stat-card">
          <div className="stat-card-header">
            <div className="stat-card-icon green">
              <Play size={18} />
            </div>
            <div className="stat-card-label">Ishlamoqda</div>
          </div>
          <div className="stat-card-value" style={{ color: 'var(--success)' }}>{stats.running}</div>
        </div>

        <div className="stat-card">
          <div className="stat-card-header">
            <div className="stat-card-icon red">
              <AlertTriangle size={18} />
            </div>
            <div className="stat-card-label">To'xtagan</div>
          </div>
          <div className="stat-card-value" style={{ color: 'var(--danger)' }}>{stats.stopped}</div>
        </div>

        <div className="stat-card">
          <div className="stat-card-header">
