              <Signal size={18} />
            </div>
            <div className="stat-card-label">Signal yo'q</div>
          </div>
          <div className="stat-card-value" style={{ color: 'var(--warning)' }}>{stats.warning}</div>
        </div>
      </div>

      {/* Filters */}
      <div className="machines-section-header">
        <div className="machines-section-title">Stanoklar</div>
        <div className="machines-filter">
