                <span>Ma'lumot</span>
              </button>
              <button 
                className={`tab-btn ${activeTab === 'diag' ? 'active' : ''}`}
                onClick={() => setActiveTab('diag')}
              >
                <Cpu size={14} />
                <span>Diagnostika</span>
