                      {getStatusText(selectedMachine.status)}
                    </div>
                  </div>
                  <div className="info-item">
                    <div className="info-item-label">Smena metrlar</div>
                    <div className="info-item-value">{selectedMachine.shift_meters?.toFixed(1) || 0}m</div>
                  </div>
                  <div className="info-item">
                    <div className="info-item-label">Asnova qoldiq</div>
                    <div className="info-item-value">{selectedMachine.remaining?.toFixed(1) || 0}m</div>
                  </div>
                </div>

                <div className="info-details">
                  <div className="detail-row">
                    <span className="detail-label">Signal</span>
                    <span className="detail-value">{selectedMachine.baud || 0} BPS</span>
                  </div>
                  <div className="detail-row">
                    <span className="detail-label">Protokol</span>
                    <span className="detail-value">{selectedMachine.protocol || 'N/A'}</span>
                  </div>
                  <div className="detail-row">
