                  <div className="detail-row">
                    <span className="detail-label">Oxirgi ko'rilgan</span>
                    <span className="detail-value">
                      {selectedMachine.last_seen ? new Date(selectedMachine.last_seen).toLocaleString('uz-UZ') : 'N/A'}
                    </span>
                  </div>
                </div>

                {(selectedMachine.remaining <= 0 || user.role === 'ADMIN' || user.role === 'UZLAVYAZ') && (
                  <div className="asnova-fill">
                    <h4>Asnova to'ldirish</h4>
                    <div className="asnova-form">
                      <input
                        type="number"
                        className="input-field"
                        placeholder="Yangi asnova uzunligi (metr)"
