                        onChange={(e) => setAsnovaLength(e.target.value)}
                      />
                      <button className="btn-primary" onClick={handleFillAsnova}>
                        To'ldirish
                      </button>
                    </div>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'diag' && (
              <div className="machine-diag">
                <div className="diag-item">
                  <div className="diag-header">
                    <span className="diag-label">RAM (Heap)</span>
                    <span className="diag-value">
                      {((selectedMachine.sys_info?.ram?.free / 1048576) || 0).toFixed(2)} MB / 
                      {((selectedMachine.sys_info?.ram?.total / 1048576) || 0).toFixed(2)} MB
                    </span>
                  </div>
                  <div className="diag-bar-bg">
                    <div 
                      className="diag-bar ram" 
                      style={{ 
                        width: `${(selectedMachine.sys_info?.ram?.total ? 
                          (selectedMachine.sys_info.ram.free / selectedMachine.sys_info.ram.total * 100) : 0)}%` 
                      }}
                    ></div>
                  </div>
                </div>

                <div className="diag-item">
                  <div className="diag-header">
                    <span className="diag-label">ROM (Flash)</span>
                    <span className="diag-value">
                      {((selectedMachine.sys_info?.rom?.free / 1048576) || 0).toFixed(2)} MB / 
                      {((selectedMachine.sys_info?.rom?.total / 1048576) || 0).toFixed(2)} MB
                    </span>
                  </div>
                  <div className="diag-bar-bg">
                    <div 
                      className="diag-bar rom" 
                      style={{ 
                        width: `${(selectedMachine.sys_info?.rom?.total ? 
                          (selectedMachine.sys_info.rom.free / selectedMachine.sys_info.rom.total * 100) : 0)}%` 
                      }}
                    ></div>
                  </div>
                </div>

                <div className="diag-grid">
                  <div className="diag-card">
                    <Cpu size={16} />
                    <div className="diag-card-label">CPU</div>
                    <div className="diag-card-value">{selectedMachine.sys_info?.cpu || 0} MHz</div>
                  </div>
                  <div className="diag-card">
                    <Wifi size={16} />
                    <div className="diag-card-label">WiFi RSSI</div>
                    <div className="diag-card-value">{selectedMachine.sys_info?.wifi?.rssi || 0} dBm</div>
                  </div>
                  <div className="diag-card">
                    <Signal size={16} />
                    <div className="diag-card-label">SSID</div>
                    <div className="diag-card-value">{selectedMachine.sys_info?.wifi?.ssid || 'N/A'}</div>
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'settings' && (
              <div className="machine-settings">
                <h4>Ulanish manbasi</h4>
                <div className="source-switcher">
                  {['AUTO', 'USB', 'WIFI'].map(source => (
                    <button
                      key={source}
                      className={`source-btn ${selectedMachine.preferred_source === source ? 'active' : ''}`}
                      onClick={() => handleSourceChange(selectedMachine.id, source)}
                    >
                      {source}
                    </button>
                  ))}
                </div>

                <div className="settings-info">
                  <p>Joriy manba: <strong>{selectedMachine.connection_source}</strong></p>
                  <p>Preferred manba: <strong>{selectedMachine.preferred_source}</strong></p>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

